import { useEffect, useRef } from "react";
import { useDatePicker, formatBasic } from "react-date-range-picker-headless";
import { useFloating, autoUpdate, offset, flip, shift, FloatingPortal } from "@floating-ui/react";
import type { DatePickerProps } from "@/lib/types";
import { cn, sizeClass } from "@/lib/utils";
import { mergeRefs } from "@/lib/merge-refs";
import { CalendarGrid } from "./calendar-grid";

export function DatePicker({
  // Visual / render props
  className,
  style,
  inline,
  hideHeader,
  hideFooter,
  hideWeekdays,
  renderTrigger,
  renderHeader,
  renderWeekdayRow,
  renderDayCell,
  renderFooter,
  // Form integration
  name,
  // Hook options (rest)
  ...options
}: DatePickerProps) {
  const picker = useDatePicker(options);
  const { locale, isOpen } = picker;
  const showContent = inline || isOpen;
  const localPopupRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (isOpen && !inline && localPopupRef.current) {
      localPopupRef.current.focus({ preventScroll: true });
    }
  }, [isOpen, inline]);

  const { refs, floatingStyles } = useFloating({
    open: !inline && isOpen,
    placement: "bottom-start",
    middleware: [offset(8), flip(), shift({ padding: 8 })],
    whileElementsMounted: autoUpdate,
  });

  const triggerEl =
    !inline &&
    (renderTrigger ? (
      renderTrigger({
        displayValue: picker.displayValue,
        placeholder: locale.placeholder,
        hasValue: picker.hasValue,
        isOpen,
        onToggle: picker.handleToggle,
        onClear: picker.handleClear,
        locale,
        triggerRef: refs.setReference as (node: HTMLElement | null) => void,
      })
    ) : (
      <button
        type="button"
        className="flex items-center justify-between min-w-[200px] px-3.5 py-2 bg-background border border-input rounded-md shadow-sm hover:border-ring/50 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:border-ring"
        onClick={picker.handleToggle}
        aria-expanded={isOpen}
        aria-haspopup="dialog"
      >
        <span className={picker.displayValue ? undefined : "text-muted-foreground"}>
          {picker.displayValue || locale.placeholder}
        </span>
        {picker.hasValue && !options.required && (
          <button
            type="button"
            className="ml-2 p-1 -m-1 appearance-none border-0 bg-transparent text-muted-foreground hover:text-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring rounded-sm cursor-pointer"
            aria-label={locale.clear}
            onClick={(e) => {
              e.stopPropagation();
              picker.handleClear();
            }}
          >
            ×
          </button>
        )}
      </button>
    ));

  const headerEl =
    !hideHeader &&
    showContent &&
    (renderHeader ? (
      renderHeader({
        month: picker.currentMonth,
        formattedMonthYear: locale.formatMonthYear(picker.currentMonth),
        onPrevMonth: picker.handlePrevMonth,
        onNextMonth: picker.handleNextMonth,
        locale,
        captionLayout: options.captionLayout ?? "buttons",
        years: picker.years,
        months: picker.months,
        onYearSelect: picker.handleYearSelect,
        onMonthSelect: picker.handleMonthSelect,
      })
    ) : options.captionLayout === "dropdown" ? (
      <div className="flex items-center justify-between mb-4">
        <button
          type="button"
          className="flex items-center justify-center w-7 h-7 text-muted-foreground rounded hover:bg-accent hover:text-accent-foreground cursor-pointer"
          onClick={picker.handlePrevMonth}
        >
          {locale.prevMonth}
        </button>
        <div>
          <select
            className="px-1 py-0.5 text-sm bg-transparent border border-transparent rounded hover:border-border focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring cursor-pointer"
            value={picker.currentMonth.getFullYear()}
            onChange={(e) => picker.handleYearSelect(Number(e.target.value))}
            aria-label="Select year"
          >
            {picker.years.map((y) => (
              <option key={y} value={y}>
                {y}
                {locale.yearLabel}
              </option>
            ))}
          </select>{" "}
          <select
            className="px-1 py-0.5 text-sm bg-transparent border border-transparent rounded hover:border-border focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring cursor-pointer"
            value={picker.currentMonth.getMonth()}
            onChange={(e) => picker.handleMonthSelect(Number(e.target.value))}
            aria-label="Select month"
          >
            {picker.months.map((m) => (
              <option key={m} value={m}>
                {locale.months[m]}
                {locale.monthLabel}
              </option>
            ))}
          </select>
        </div>
        <button
          type="button"
          className="flex items-center justify-center w-7 h-7 text-muted-foreground rounded hover:bg-accent hover:text-accent-foreground cursor-pointer"
          onClick={picker.handleNextMonth}
        >
          {locale.nextMonth}
        </button>
      </div>
    ) : (
      <div className="flex items-center justify-between mb-4">
        <button
          type="button"
          className="flex items-center justify-center w-7 h-7 text-muted-foreground rounded hover:bg-accent hover:text-accent-foreground cursor-pointer"
          onClick={picker.handlePrevMonth}
        >
          {locale.prevMonth}
        </button>
        <span className="font-semibold text-[15px]">
          {locale.formatMonthYear(picker.currentMonth)}
        </span>
        <button
          type="button"
          className="flex items-center justify-center w-7 h-7 text-muted-foreground rounded hover:bg-accent hover:text-accent-foreground cursor-pointer"
          onClick={picker.handleNextMonth}
        >
          {locale.nextMonth}
        </button>
      </div>
    ));

  const footerEl =
    !hideFooter &&
    showContent &&
    (renderFooter ? (
      renderFooter({
        canConfirm: picker.canConfirm,
        hasValue: picker.hasValue,
        onConfirm: picker.handleConfirm,
        onCancel: picker.handleCancel,
        onClear: picker.handleClear,
        locale,
      })
    ) : (
      <div className="flex justify-end gap-2 mt-4 pt-4 border-t border-border">
        {picker.hasValue && (
          <button
            type="button"
            className="px-3 py-1.5 text-sm text-muted-foreground hover:text-foreground hover:bg-accent rounded-md transition-colors cursor-pointer"
            onClick={picker.handleClear}
          >
            {locale.clear}
          </button>
        )}
        <button
          type="button"
          className="px-3 py-1.5 text-sm text-muted-foreground hover:text-foreground hover:bg-accent rounded-md transition-colors cursor-pointer"
          onClick={picker.handleCancel}
        >
          {locale.cancel}
        </button>
        <button
          type="button"
          className="px-3 py-1.5 text-sm text-primary-foreground bg-primary hover:bg-primary/90 rounded-md transition-colors disabled:opacity-50 disabled:pointer-events-none cursor-pointer"
          onClick={picker.handleConfirm}
          disabled={!picker.canConfirm}
        >
          {locale.confirm}
        </button>
      </div>
    ));

  const calendarContent = (
    <>
      {headerEl}
      {picker.calendars.map((cal) => (
        <CalendarGrid
          key={formatBasic(cal.month, "YYYY-MM")}
          calendar={cal}
          locale={locale}
          focusedDate={picker.focusedDate}
          getDayProps={picker.getDayProps}
          onDateClick={picker.handleDateClick}
          showTitle={(options.numberOfMonths ?? 1) > 1}
          hideWeekdays={hideWeekdays}
          captionLayout={options.captionLayout}
          years={picker.years}
          monthOptions={picker.months}
          onYearSelect={picker.handleYearSelect}
          onMonthSelect={picker.handleMonthSelect}
          renderWeekdayRow={renderWeekdayRow}
          renderDayCell={renderDayCell}
        />
      ))}
      {footerEl}
    </>
  );

  return (
    <div
      ref={mergeRefs(picker.containerRef, refs.setReference)}
      className={cn(
        "relative w-max font-sans text-[13px] text-foreground select-none",
        sizeClass(options.size),
        className,
      )}
      style={style}
    >
      {name && (
        <input
          type="hidden"
          name={name}
          value={options.value ? formatBasic(options.value, "YYYY-MM-DD") : ""}
        />
      )}
      {triggerEl}

      {showContent && !inline && (
        <FloatingPortal>
          <div
            ref={mergeRefs(refs.setFloating, picker.popupRef, localPopupRef)}
            style={floatingStyles}
            className="z-50 p-4 bg-popover border border-border rounded-lg shadow-md"
            onKeyDown={picker.handleKeyDown}
            tabIndex={0}
            role="dialog"
            aria-modal="true"
            aria-label={locale.placeholder}
            aria-activedescendant={
              picker.focusedDate ? `rdrp-day-${locale.formatDate(picker.focusedDate)}` : undefined
            }
          >
            {calendarContent}
          </div>
        </FloatingPortal>
      )}

      {showContent && inline && (
        <div
          className="p-4 bg-popover border border-border rounded-lg"
          onKeyDown={picker.handleKeyDown}
          tabIndex={0}
          role="group"
          aria-label={locale.placeholder}
          aria-activedescendant={
            picker.focusedDate ? `rdrp-day-${locale.formatDate(picker.focusedDate)}` : undefined
          }
        >
          {calendarContent}
        </div>
      )}
    </div>
  );
}

import type { CalendarGridProps } from "@/lib/types";
import { cn } from "@/lib/utils";
import { CalendarGridInternal } from "@/lib/calendar-grid-internal";

export function CalendarGrid(props: CalendarGridProps) {
  return (
    <CalendarGridInternal
      {...props}
      cn={cn}
      classNames={{
        calendarPanel: "flex flex-col",
        header: "flex items-center justify-between mb-4",
        headerTitle: "font-semibold text-[15px]",
        captionSelect:
          "px-1 py-0.5 text-sm bg-transparent border border-transparent rounded hover:border-border focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring cursor-pointer",
        weekdays: "flex mb-2",
        weekday:
          "flex items-center justify-center w-9 h-7 text-xs font-medium text-muted-foreground uppercase",
        grid: "flex flex-col gap-1",
        week: "flex",
        day: "flex items-center justify-center w-9 h-9 mx-[1px] rounded-md transition-colors cursor-pointer hover:bg-accent hover:text-accent-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-1 focus-visible:ring-offset-background",
        dayEmpty: "pointer-events-none",
        dayToday: "font-bold text-primary",
        daySelected: "bg-primary text-primary-foreground font-semibold hover:bg-primary/90",
        dayDisabled: "text-muted-foreground opacity-50 pointer-events-none",
        dayOutside: "text-muted-foreground",
        dayHighlighted:
          "relative after:absolute after:bottom-1 after:w-1 after:h-1 after:bg-amber-500 dark:after:bg-amber-400 after:rounded-full",
        dayInRange: "bg-primary/10 text-accent-foreground rounded-none mx-0 hover:bg-primary/15",
        dayRangeStart: "bg-primary text-primary-foreground rounded-r-none mx-0 hover:bg-primary/90",
        dayRangeEnd: "bg-primary text-primary-foreground rounded-l-none mx-0 hover:bg-primary/90",
        dayHoverRange: "bg-primary/5 text-accent-foreground rounded-none mx-0",
        dayHoverTarget: "bg-primary/20 text-accent-foreground",
        dayFocused: "ring-2 ring-ring ring-offset-1 ring-offset-background",
      }}
    />
  );
}

import { clsx, type ClassValue } from "clsx";
import { twMerge } from "tailwind-merge";
import type { DatePickerSize } from "react-date-range-picker-headless";

/** Merge class names with Tailwind conflict resolution. */
export function cn(...args: ClassValue[]): string {
  return twMerge(clsx(args));
}

/** Return the size modifier class. Uses data-slot attributes for descendant targeting. */
export function sizeClass(size: DatePickerSize = "medium"): string {
  const sizeMap: Record<DatePickerSize, string> = {
    small:
      'text-xs [&_[data-slot="day"]]:w-7 [&_[data-slot="day"]]:h-7 [&_[data-slot="time-item"]]:text-xs [&_[data-slot="time-item"]]:h-6 [&_[data-slot="time-panel"]]:w-48',
    medium:
      'text-sm [&_[data-slot="day"]]:w-9 [&_[data-slot="day"]]:h-9 [&_[data-slot="time-item"]]:text-sm [&_[data-slot="time-item"]]:h-8 [&_[data-slot="time-panel"]]:w-56',
    large:
      'text-base [&_[data-slot="day"]]:w-11 [&_[data-slot="day"]]:h-11 [&_[data-slot="time-item"]]:text-base [&_[data-slot="time-item"]]:h-10 [&_[data-slot="time-panel"]]:w-64',
    "x-large":
      'text-lg [&_[data-slot="day"]]:w-12 [&_[data-slot="day"]]:h-12 [&_[data-slot="time-item"]]:text-lg [&_[data-slot="time-item"]]:h-12 [&_[data-slot="time-panel"]]:w-72',
  };
  return sizeMap[size] || sizeMap["medium"];
}

import type { CSSProperties, ReactNode } from "react";
import type {
  Locale,
  DayProps,
  DatePickerSize,
  DateRangePreset,
  CaptionLayout,
  CalendarMonth,
  UseDatePickerOptions,
  UseDateRangePickerOptions,
  UseDateTimePickerOptions,
  UseDateRangeTimePickerOptions,
  TimeConfig,
  TimePeriod,
} from "react-date-range-picker-headless";
// ── Render prop context types ──

export interface TriggerRenderProps {
  displayValue: string;
  placeholder: string;
  hasValue: boolean;
  isOpen: boolean;
  onToggle: () => void;
  onClear: () => void;
  locale: Locale;
  triggerRef: (node: HTMLElement | null) => void;
}

export interface HeaderRenderProps {
  month: Date;
  formattedMonthYear: string;
  onPrevMonth: () => void;
  onNextMonth: () => void;
  locale: Locale;
  captionLayout: CaptionLayout;
  years: number[];
  months: number[];
  onYearSelect: (year: number) => void;
  onMonthSelect: (month: number) => void;
}

export interface WeekdayRowRenderProps {
  weekdays: string[];
}

export interface DayCellRenderProps extends DayProps {
  id: string;
  onClick: () => void;
  onMouseEnter?: () => void;
  onMouseLeave?: () => void;
}

export interface FooterRenderProps {
  canConfirm: boolean;
  hasValue: boolean;
  onConfirm: () => void;
  onCancel: () => void;
  onClear: () => void;
  locale: Locale;
}

export interface TimeSectionRenderProps {
  displayValue: string;
  label: string;
  timeConfig: Required<TimeConfig>;
  hour: number;
  minute: number;
  second: number;
  period: TimePeriod;
}

export interface PresetsBarRenderProps {
  presets: DateRangePreset[];
  activePresetIndex: number;
  onPresetClick: (preset: DateRangePreset) => void;
}

// ── Shared visual/render props ──

export interface RenderProps {
  renderTrigger?: (props: TriggerRenderProps) => ReactNode;
  renderHeader?: (props: HeaderRenderProps) => ReactNode;
  renderWeekdayRow?: (props: WeekdayRowRenderProps) => ReactNode;
  renderDayCell?: (props: DayCellRenderProps) => ReactNode;
  renderFooter?: (props: FooterRenderProps) => ReactNode;
  renderTimeSection?: (props: TimeSectionRenderProps) => ReactNode;
  renderPresetsBar?: (props: PresetsBarRenderProps) => ReactNode;
}

export interface VisualProps {
  className?: string;
  style?: CSSProperties;
  inline?: boolean;
  hideHeader?: boolean;
  hideFooter?: boolean;
  hideWeekdays?: boolean;
}

// ── Form integration props ──

export interface FormNameProps {
  name?: string;
}

export interface RangeFormNameProps extends FormNameProps {
  endName?: string;
}

// ── Public component props ──

export interface DatePickerProps extends UseDatePickerOptions, VisualProps, RenderProps, FormNameProps {}

export interface DateRangePickerProps extends UseDateRangePickerOptions, VisualProps, RenderProps, RangeFormNameProps {}

export interface DateTimePickerProps extends UseDateTimePickerOptions, VisualProps, RenderProps, FormNameProps {}

export interface DateRangeTimePickerProps
  extends UseDateRangeTimePickerOptions, VisualProps, Omit<RenderProps, "renderTimeSection">, RangeFormNameProps {
  renderTimeSection?: (props: RangeTimeSectionRenderProps) => ReactNode;
}

import type { UseStandaloneTimePickerOptions } from "react-date-range-picker-headless";

export interface TimePickerPanelProps extends UseStandaloneTimePickerOptions {
  size?: DatePickerSize;
  className?: string;
  style?: CSSProperties;
  hideFooter?: boolean;
  renderFooter?: (props: FooterRenderProps) => ReactNode;
}

// ── Internal CalendarGrid props ──

export interface CalendarGridProps {
  calendar: CalendarMonth;
  locale: Locale;
  focusedDate?: Date | null;
  getDayProps: (date: Date, referenceMonth?: Date) => DayProps;
  onDateClick: (date: Date) => void;
  onDateHover?: (date: Date | null) => void;
  showTitle?: boolean;
  hideWeekdays?: boolean;
  captionLayout?: CaptionLayout;
  years?: number[];
  monthOptions?: number[];
  onYearSelect?: (year: number, calendarIndex?: number) => void;
  onMonthSelect?: (month: number, calendarIndex?: number) => void;
  calendarIndex?: number;
  renderWeekdayRow?: (props: WeekdayRowRenderProps) => ReactNode;
  renderDayCell?: (props: DayCellRenderProps) => ReactNode;
}

// ── Internal TimePanelInternal props ──

export interface TimePanelInternalProps {
  hour: number;
  minute: number;
  second: number;
  period: TimePeriod;
  onHourChange: (h: number) => void;
  onMinuteChange: (m: number) => void;
  onSecondChange: (s: number) => void;
  onPeriodChange: (p: TimePeriod) => void;
  timeConfig: Required<TimeConfig>;
}

import type { ReactNode } from "react";
import type { ClassValue } from "clsx";
import type {
  CalendarMonth,
  DayProps,
  Locale,
  CaptionLayout,
} from "react-date-range-picker-headless";

export interface InternalCalendarGridProps {
  calendar: CalendarMonth;
  locale: Locale;
  focusedDate?: Date | null;
  getDayProps: (date: Date, referenceMonth?: Date) => DayProps;
  onDateClick: (date: Date) => void;
  onDateHover?: (date: Date | null) => void;
  showTitle?: boolean;
  hideWeekdays?: boolean;
  captionLayout?: CaptionLayout;
  years?: number[];
  monthOptions?: number[];
  onYearSelect?: (year: number, calendarIndex: number) => void;
  onMonthSelect?: (month: number, calendarIndex: number) => void;
  calendarIndex?: number;
  renderWeekdayRow?: (props: { weekdays: string[] }) => ReactNode;
  renderDayCell?: (
    props: DayProps & {
      id: string;
      onClick: () => void;
      onMouseEnter?: () => void;
      onMouseLeave?: () => void;
    },
  ) => ReactNode;

  // Class overrides
  classNames?: {
    calendarPanel?: string;
    header?: string;
    headerTitle?: string;
    captionSelect?: string;
    weekdays?: string;
    weekday?: string;
    grid?: string;
    week?: string;
    day?: string;
    dayEmpty?: string;
    dayToday?: string;
    daySelected?: string;
    dayDisabled?: string;
    dayOutside?: string;
    dayHighlighted?: string;
    dayInRange?: string;
    dayRangeStart?: string;
    dayRangeEnd?: string;
    dayHoverRange?: string;
    dayHoverTarget?: string;
    dayRangeSingle?: string;
    dayFocused?: string;
  };
  idPrefix?: string;
  cn: (...args: ClassValue[]) => string;
}

export function CalendarGridInternal({
  calendar,
  locale,
  focusedDate,
  getDayProps,
  onDateClick,
  onDateHover,
  showTitle,
  hideWeekdays,
  captionLayout,
  years,
  monthOptions,
  onYearSelect,
  onMonthSelect,
  calendarIndex = 0,
  renderWeekdayRow,
  renderDayCell,
  classNames = {},
  idPrefix,
  cn,
}: InternalCalendarGridProps) {
  const weekdayRow = hideWeekdays ? null : renderWeekdayRow ? (
    renderWeekdayRow({ weekdays: locale.weekdays })
  ) : (
    <div className={classNames.weekdays} role="row">
      {locale.weekdays.map((wd) => (
        <div key={wd} className={classNames.weekday} role="columnheader">
          {wd}
        </div>
      ))}
    </div>
  );

  const titleContent = showTitle ? (
    captionLayout === "dropdown" && years && monthOptions && onYearSelect && onMonthSelect ? (
      <div className={classNames.header}>
        <div>
          <select
            className={classNames.captionSelect}
            value={calendar.month.getFullYear()}
            onChange={(e) => onYearSelect(Number(e.target.value), calendarIndex)}
            aria-label={locale.selectYearLabel}
          >
            {years.map((y) => (
              <option key={y} value={y}>
                {y}
                {locale.yearLabel}
              </option>
            ))}
          </select>{" "}
          <select
            className={classNames.captionSelect}
            value={calendar.month.getMonth()}
            onChange={(e) => onMonthSelect(Number(e.target.value), calendarIndex)}
            aria-label={locale.selectMonthLabel}
          >
            {monthOptions.map((m) => (
              <option key={m} value={m}>
                {locale.months[m]}
                {locale.monthLabel}
              </option>
            ))}
          </select>
        </div>
      </div>
    ) : (
      <div className={classNames.header}>
        <span className={classNames.headerTitle}>{locale.formatMonthYear(calendar.month)}</span>
      </div>
    )
  ) : null;

  return (
    <div className={classNames.calendarPanel}>
      {titleContent}
      {weekdayRow}
      <div
        className={classNames.grid}
        role="grid"
        aria-label={locale.formatMonthYear(calendar.month)}
        aria-rowcount={calendar.weeks.length}
        aria-colcount={7}
      >
        {calendar.weeks.map((week, wi) => (
          <div
            key={`w-${calendar.month.getFullYear()}-${calendar.month.getMonth()}-${wi}`}
            className={classNames.week}
            role="row"
          >
            {week.map((day, di) => {
              if (!day) {
                return (
                  <div
                    key={`empty-${wi}-${di}`}
                    role="gridcell"
                    className={cn(classNames.day, classNames.dayEmpty)}
                    aria-hidden="true"
                  />
                );
              }

              const props = getDayProps(day, calendar.month);
              const isFocused = focusedDate ? props.isFocused : props.isToday;
              const dayKey = `${day.getFullYear()}-${day.getMonth()}-${day.getDate()}`;

              const dayId = idPrefix
                ? `rdrp-${idPrefix}-day-${locale.formatDate(day)}`
                : `rdrp-day-${locale.formatDate(day)}`;

              const cellProps = {
                ...props,
                id: dayId,
                onClick: () => onDateClick(day),
                onMouseEnter: onDateHover ? () => onDateHover(day) : undefined,
                onMouseLeave: onDateHover ? () => onDateHover(null) : undefined,
              };

              if (renderDayCell) {
                return (
                  <div
                    key={dayKey}
                    id={dayId}
                    className={classNames.day}
                    role="gridcell"
                    aria-selected={
                      props.isSelected ||
                      props.isRangeStart ||
                      props.isRangeEnd ||
                      props.isRangeSingle
                    }
                    aria-disabled={props.isDisabled}
                  >
                    {renderDayCell(cellProps)}
                  </div>
                );
              }

              return (
                <button
                  type="button"
                  key={dayKey}
                  data-slot="day"
                  id={dayId}
                  ref={(el) => {
                    if (el && isFocused) {
                      const isPickerFocused = el
                        .closest("[role='dialog'], [role='group']")
                        ?.contains(document.activeElement);
                      if (isPickerFocused && document.activeElement !== el) {
                        el.focus({ preventScroll: true });
                      }
                    }
                  }}
                  role="gridcell"
                  className={cn(
                    classNames.day,
                    props.isToday && classNames.dayToday,
                    props.isSelected && classNames.daySelected,
                    props.isDisabled && classNames.dayDisabled,
                    props.isOutsideDay && classNames.dayOutside,
                    props.isHighlighted && classNames.dayHighlighted,
                    props.isInRange && classNames.dayInRange,
                    props.isRangeStart && classNames.dayRangeStart,
                    props.isRangeEnd && classNames.dayRangeEnd,
                    props.isRangeSingle && classNames.dayRangeSingle,
                    props.isInHoverRange && classNames.dayHoverRange,
                    props.isHoverTarget && classNames.dayHoverTarget,
                    isFocused && classNames.dayFocused,
                  )}
                  disabled={props.isDisabled}
                  onClick={() => onDateClick(day)}
                  onMouseEnter={onDateHover ? () => onDateHover(day) : undefined}
                  onMouseLeave={onDateHover ? () => onDateHover(null) : undefined}
                  tabIndex={isFocused ? 0 : -1}
                  aria-label={locale.formatDate(day)}
                  aria-current={props.isToday ? "date" : undefined}
                  aria-selected={
                    props.isSelected ||
                    props.isRangeStart ||
                    props.isRangeEnd ||
                    props.isRangeSingle
                  }
                  aria-disabled={props.isDisabled}
                >
                  {props.day}
                </button>
              );
            })}
          </div>
        ))}
      </div>
    </div>
  );
}

import type { Ref, MutableRefObject } from "react";

export function mergeRefs<T>(...refs: (Ref<T> | undefined)[]) {
  return (node: T | null) => {
    refs.forEach((ref) => {
      if (typeof ref === "function") {
        ref(node);
      } else if (ref) {
        (ref as MutableRefObject<T | null>).current = node;
      }
    });
  };
}
